export function StatusBar({
  mode = 'plan',
  viewLabel,
  viewDetails = [],
  level,
  levels = [],
  onLevelChange,
  toolLabel,
  snapModes = [],
  onSnapToggle,
  gridOn = true,
  onGridToggle,
  cursorMm,
  undoDepth,
  redoDepth,
  onUndo,
  onRedo,
