/** Resolve a key event to a mode jump, or `null` if unrelated. */
export function modeForHotkey(eventKey: string): WorkspaceMode | null {
  const match = MODE_HOTKEYS.find((m) => m.hotkey === eventKey);
  return match?.mode ?? null;
}

