  if (outline.length < 4) return group;

  const shape = new THREE.Shape();
  shape.moveTo(ux(outline[0]!.xMm), -uz(outline[0]!.yMm));
  for (let i = 1; i < outline.length; i++) {
    shape.lineTo(ux(outline[i]!.xMm), -uz(outline[i]!.yMm));
  }
  shape.closePath();

