  onNavigateToSheet,
  onUndo,
  onRedo,
  canUndo,
  canRedo,
  onSectionShortcut,
  onMeasureShortcut,
  onDimensionShortcut,
  onTagByCategoryShortcut,
  thinLinesEnabled,
  onToggleThinLines,
  tabs,
  activeTabId,
  onTabActivate,
  onTabClose,
  onTabAdd,
  onTabReorder,
  onCloseInactiveTabs,
}: TopBarProps): JSX.Element {
  const tablistId = useId();
